class RiskRegister:
    """In-memory risk register; back with a database in production."""

    def __init__(self):
        self._entries: dict[str, RiskEntry] = {}

    def add(self, entry: RiskEntry) -> RiskEntry:
        self._entries[entry.risk_id] = entry
        return entry

    def get(self, risk_id: str) -> Optional[RiskEntry]:
        return self._entries.get(risk_id)

    def by_category(self, category: RiskCategory) -> list[RiskEntry]:
        return [e for e in self._entries.values() if e.category == category]

    def by_rating(self, rating: str) -> list[RiskEntry]:
        return [e for e in self._entries.values() if e.residual_rating == rating]

    def critical_open(self) -> list[RiskEntry]:
        return [
            e for e in self._entries.values()
            if e.residual_rating == "critical" and e.status == RiskStatus.OPEN
        ]

    def summary(self) -> dict:
        counts = {"low": 0, "medium": 0, "high": 0, "critical": 0}
        for e in self._entries.values():
            counts[e.residual_rating] += 1
        return {"total": len(self._entries), **counts}
